SELECT type, COUNT(*) as count
FROM genetic_elements
GROUP BY type;

SELECT name, element_id
FROM genetic_elements
WHERE type = 'PolyA_signal';

SELECT *
FROM genetic_elements
WHERE size_bp > (SELECT AVG(size_bp) FROM genetic_elements);

SELECT DISTINCT u.user_name 
FROM users u
INNER JOIN construct_sharing cs ON u.user_id = cs.shared_by;

SELECT DISTINCT users.user_name, users.department
FROM users
JOIN constructs ON users.user_id = constructs.created_by;
